1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const survives = (count: number, isAlive: boolean): boolean =>
6	  count === 3 || (count === 2 && isAlive);
7	
8	export function nextGeneration(liveCells: Cell[]): Cell[] {
9	  const liveSet = new Set(liveCells.map(cellKey));
10	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
11	
12	  for (const [x, y] of liveCells) {
13	    for (let dx = -1; dx <= 1; dx++) {
14	      for (let dy = -1; dy <= 1; dy++) {
15	        if (dx === 0 && dy === 0) continue;
16	        const cell: Cell = [x + dx, y + dy];
17	        const key = cellKey(cell);
18	        const entry = neighborCounts.get(key) ?? { cell, count: 0 };
19	        entry.count++;
20	        neighborCounts.set(key, entry);
21	      }
22	    }
23	  }
24	
25	  const result: Cell[] = [];
26	  for (const [key, { cell, count }] of neighborCounts) {
27	    if (survives(count, liveSet.has(key))) {
28	      result.push(cell);
29	    }
30	  }
31	  return result;
32	}
